def divisors_with_phi(fac):
    res = []
    def dfs(i, val, ph):
        if i == len(fac):
            res.append((val, ph))
            return
        p, e = fac[i]
        for k in range(0, e + 1):
            val *= p
            ph += (p ** k - p ** (k - 1) if k > 0 else 0)
        dfs(i + 1, val, ph)
    dfs(0, 1, 0)
    return res

