def divisors_with_phi(fac):
    res = []
    def dfs(i, val, ph):
        if i == len(fac):
            res.append((val, ph))
            return
        p, e = fac[i]
        for k in range(0, e + 1):
            val_k = val * (p ** k)
            phi_k = (p ** k)
            dfs(i + 1, val_k, ph * phi_k)
    dfs(0, 1, 1)
    return res

